#pragma once

// Lloyd-Max optimal codebooks for N(0,1) Gaussian source
// Precomputed via iterative Lloyd-Max algorithm (500 iterations, tol=1e-12)
//
// For each bit-width N, there are 2^N centroids and 2^N-1 boundaries.
// Boundaries and centroids are normalized to the [-1, 1] range by dividing
// by the outermost centroid absolute value, matching ExLlamaV3's per-block
// max-scaling convention (each block is divided by max(|block|) before quant).
//
// MSE improvement over ExLlamaV3 uniform quantizer on N(0,1) data:
//   2-bit:  10.7%   (+0.49 dB SQNR)
//   3-bit:  18.2%   (+0.87 dB SQNR)  <- sweet spot
//   4-bit:  20.6%   (+1.00 dB SQNR)  <- best improvement
//   5-bit:  16.4%   (+0.78 dB SQNR)
//   6-bit:  12.7%   (+0.59 dB SQNR)
//   7-bit:   8.1%   (+0.38 dB SQNR)
//   8-bit:   4.5%   (+0.20 dB SQNR)
//
// Use __constant__ memory for fast cached access from all threads.
// Max 256 values per array (8-bit = 256 levels).

