// ---------------------------------------------------------------------------
// Dispatch: lm_quantize
//
// Find the index of the nearest Lloyd-Max centroid for value v in [-1, 1]
// by binary searching the boundaries array.
// Returns integer code in [0, 2^num_bits - 1].
// ---------------------------------------------------------------------------

__device__ __forceinline__ int lm_quantize(float v, int num_bits)
{
    int lo = 0;
    int hi;
    const float* bounds;

    switch (num_bits)
    {
        case 2:  hi = 3;   bounds = lm_boundaries_2bit; break;
        case 3:  hi = 7;   bounds = lm_boundaries_3bit; break;
        case 4:  hi = 15;  bounds = lm_boundaries_4bit; break;
        case 5:  hi = 31;  bounds = lm_boundaries_5bit; break;
        case 6:  hi = 63;  bounds = lm_boundaries_6bit; break;
        case 7:  hi = 127; bounds = lm_boundaries_7bit; break;
        default: hi = 255; bounds = lm_boundaries_8bit; break;
    }

    // Binary search over boundary array (length = 2^num_bits - 1)
    // Returns the index of the first boundary >= v, which is the centroid index
    while (lo < hi)
    {
        int mid = (lo + hi) >> 1;
        if (v > bounds[mid])
            lo = mid + 1;
        else
            hi = mid;
    }
    return lo;
}

// ---------------------------------------------------------------------------
// Dispatch: lm_dequantize
//
// Look up the Lloyd-Max centroid for integer code in [-1, 1] range.
// ---------------------------------------------------------------------------

__device__ __forceinline__ float lm_dequantize(int code, int num_bits)
{
    switch (num_bits)
    {
        case 2:  return lm_centroids_2bit[code];
        case 3:  return lm_centroids_3bit[code];
        case 4:  return lm_centroids_4bit[code];
        case 5:  return lm_centroids_5bit[code];
        case 6:  return lm_centroids_6bit[code];
        case 7:  return lm_centroids_7bit[code];
        default: return lm_centroids_8bit[code];
    }
}
